    await appendRunEvent(finalizedRun, await nextRunEventSeq(finalizedRun.id), {
      eventType: "lifecycle",
      stream: "system",
      level: "error",
      message: shouldRetry
        ? `${baseMessage}; queued retry ${retriedRun?.id ?? ""}`.trim()
