      payload: {
        ...(run.processPid ? { processPid: run.processPid } : {}),
        ...(retriedRun ? { retryRunId: retriedRun.id } : {}),
      },
    });

    await finalizeAgentStatus(run.agentId, "failed");
    await startNextQueuedRunForAgent(run.agentId);
